import xml.etree.ElementTree as ET
from xml.dom import minidom
from io import BytesIO, StringIO
import os


def validate_and_read_xml(file_input, schema_file=None, max_size_mb=10):
    """
    Reads and validates an XML document from various input sources.
    
    Args:
        file_input: Can be a file path (str), file object, or bytes
        schema_file: Optional path to XSD schema file for validation
        max_size_mb: Maximum file size in megabytes (default 10MB)
    
    Returns:
        dict: Contains parsed XML tree, validation status, and any errors
    """
    result = {
        'valid': False,
        'tree': None,
        'root': None,
        'errors': [],
        'warnings': []
    }
    
    try:
        # Handle different input types
        if isinstance(file_input, str):
            # File path
            if not os.path.exists(file_input):
                result['errors'].append(f"File not found: {file_input}")
                return result
            
            file_size = os.path.getsize(file_input)
            if file_size > max_size_mb * 1024 * 1024:
                result['errors'].append(f"File size exceeds {max_size_mb}MB limit")
                return result
            
            with open(file_input, 'rb') as f:
                content = f.read()
        
        elif isinstance(file_input, bytes):
            # Bytes input
            if len(file_input) > max_size_mb * 1024 * 1024:
                result['errors'].append(f"File size exceeds {max_size_mb}MB limit")
                return result
            content = file_input
        
        elif hasattr(file_input, 'read'):
            # File-like object
            content = file_input.read()
            if isinstance(content, str):
                content = content.encode('utf-8')
            
            if len(content) > max_size_mb * 1024 * 1024:
                result['errors'].append(f"File size exceeds {max_size_mb}MB limit")
                return result
        
        else:
            result['errors'].append("Invalid input type. Expected file path, bytes, or file object")
            return result
        
        # Check if content is empty
        if not content or len(content.strip()) == 0:
            result['errors'].append("Empty XML content")
            return result
        
        # Check for common XML issues
        content_str = content.decode('utf-8') if isinstance(content, bytes) else content
        
        # Basic validation checks
        if not content_str.strip().startswith('<?xml') and not content_str.strip().startswith('<'):
            result['errors'].append("Content does not appear to be valid XML")
            return result
        
        # Parse XML
        try:
            tree = ET.ElementTree(ET.fromstring(content))
            root = tree.getroot()
            result['tree'] = tree
            result['root'] = root
        except ET.ParseError as e:
            result['errors'].append(f"XML parsing error: {str(e)}")
            return result
        
        # Validate against XSD schema if provided
        if schema_file:
            try:
                from lxml import etree
                
                # Parse XSD schema
                with open(schema_file, 'rb') as f:
                    schema_root = etree.XML(f.read())
                    schema = etree.XMLSchema(schema_root)
                
                # Parse XML with lxml for validation
                xml_doc = etree.fromstring(content)
                
                # Validate
                if not schema.validate(xml_doc):
                    for error in schema.error_log:
                        result['errors'].append(f"Schema validation error: {error.message}")
                    return result
                    
            except ImportError:
                result['warnings'].append("lxml not installed. Schema validation skipped.")
            except Exception as e:
                result['errors'].append(f"Schema validation error: {str(e)}")
                return result
        
        # Check for XML bombs (excessive nesting or entities)
        if _check_xml_depth(root) > 100:
            result['warnings'].append("XML document has excessive nesting depth")
        
        # If we got here, validation passed
        result['valid'] = True
        
    except UnicodeDecodeError as e:
        result['errors'].append(f"Encoding error: {str(e)}")
    except Exception as e:
        result['errors'].append(f"Unexpected error: {str(e)}")
    
    return result


def _check_xml_depth(element, depth=0):
    """Helper function to check XML nesting depth"""
    if not list(element):
        return depth
    return max(_check_xml_depth(child, depth + 1) for child in element)


def extract_xml_data(xml_result):
    """
    Extract data from validated XML result.
    
    Args:
        xml_result: Result dictionary from validate_and_read_xml
    
    Returns:
        dict: Dictionary representation of XML data
    """
    if not xml_result['valid'] or xml_result['root'] is None:
        return None
    
    def element_to_dict(element):
        result = {}
        
        # Add attributes
        if element.attrib:
            result['@attributes'] = dict(element.attrib)
        
        # Add text content
        if element.text and element.text.strip():
            if len(element) == 0:
                return element.text.strip()
            result['#text'] = element.text.strip()
        
        # Add children
        for child in element:
            child_data = element_to_dict(child)
            
            if child.tag in result:
                if not isinstance(result[child.tag], list):
                    result[child.tag] = [result[child.tag]]
                result[child.tag].append(child_data)
            else:
                result[child.tag] = child_data
        
        return result if result else None
    
    root = xml_result['root']
    return {root.tag: element_to_dict(root)}


def pretty_print_xml(xml_result):
    """
    Pretty print the validated XML.
    
    Args:
        xml_result: Result dictionary from validate_and_read_xml
    
    Returns:
        str: Pretty-printed XML string
    """
    if not xml_result['valid'] or xml_result['tree'] is None:
        return None
    
    xml_str = ET.tostring(xml_result['root'], encoding='unicode')
    dom = minidom.parseString(xml_str)
    return dom.toprettyxml(indent="  ")